/* BTEmptyState — organism for empty / error states.
   Figma node 3688:2647 — 7 variants: 400, 401, 404, 500, under-maintenance, no-data, no-result. */

/* ── Container ───────────────────────────────────────────────────── */
.bt-empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  box-sizing: border-box;
}

/* Error variants: fixed 400px width, 12px gap */
.bt-empty-state--error {
  width: 400px;
  gap: var(--space-md, 12px);
}

/* Simple variants (no-data / no-result): auto width, 16px gap, small padding */
.bt-empty-state--simple {
  gap: var(--space-lg, 16px);
  padding: var(--space-sm, 8px);
}

/* ── Illustration ────────────────────────────────────────────────── */
.bt-empty-state__illus {
  flex-shrink: 0;
}

.bt-empty-state--error .bt-empty-state__illus {
  width: 226px;
  height: 226px;
}

.bt-empty-state--simple .bt-empty-state__illus {
  width: 92px;
  height: 98px;
}

.bt-empty-state__illus-img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  display: block;
}

/* Theme-aware illustration: default (light) shows light asset, hides dark.
   Under [data-mode="dark"] (set on <html>) the swap is reversed. */
.bt-empty-state__illus-img--dark {
  display: none;
}

[data-mode='dark'] .bt-empty-state__illus-img--light {
  display: none;
}

[data-mode='dark'] .bt-empty-state__illus-img--dark {
  display: block;
}

/* ── Text wrapper (error variants) ──────────────────────────────── */
.bt-empty-state__text {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm, 8px);
  align-items: center;
  text-align: center;
  width: 100%;
  flex-shrink: 0;
}

.bt-empty-state__title {
  font-family: var(--typography-font-family-sans);
  font-weight: 700;
  font-size: var(--font-size-md, 16px);
  line-height: var(--line-height-sm, 20px);
  color: var(--text-primary);
  width: 100%;
  word-break: break-word;
  margin: 0;
}

.bt-empty-state__subtext {
  font-family: var(--typography-font-family-sans);
  font-weight: 500;
  font-size: var(--font-size-sm, 14px);
  line-height: var(--line-height-xs, 16px);
  color: var(--text-secondary);
  width: 100%;
  word-break: break-word;
  margin: 0;
}

.bt-empty-state__error-msg {
  font-family: var(--typography-font-family-sans);
  font-weight: 500;
  font-size: var(--font-size-sm, 14px);
  line-height: var(--line-height-xs, 16px);
  color: var(--text-tertiary);
  width: 100%;
  word-break: break-word;
  margin: 0;
}

/* ── Simple label (no-data / no-result) ─────────────────────────── */
.bt-empty-state__label {
  font-family: var(--typography-font-family-sans);
  font-weight: 500;
  font-size: var(--font-size-sm, 14px);
  line-height: var(--line-height-xs, 16px);
  color: var(--text-secondary);
  text-align: center;
  white-space: nowrap;
  flex-shrink: 0;
  margin: 0;
}

import './BTEmptyState.css';
import { BTButton } from '../button/BTButton';
import type { BTEmptyStateProps, BTEmptyStateVariant } from './BTEmptyState.types';
import { EMPTY_STATE_DEFAULTS, ERROR_VARIANTS } from './BTEmptyState.types';

// Illustrations are theme-aware SVGs. Both light & dark are rendered;
// CSS toggles visibility via the [data-mode="dark"] ancestor selector.
import illus400Light from '@btech/assets/illus/illus-400-light.svg';
import illus400Dark  from '@btech/assets/illus/illus-400-dark.svg';
import illus401Light from '@btech/assets/illus/illus-401-light.svg';
import illus401Dark  from '@btech/assets/illus/illus-401-dark.svg';
import illus404Light from '@btech/assets/illus/illus-404-light.svg';
import illus404Dark  from '@btech/assets/illus/illus-404-dark.svg';
import illus500Light from '@btech/assets/illus/illus-500-light.svg';
import illus500Dark  from '@btech/assets/illus/illus-500-dark.svg';
import illusMLight   from '@btech/assets/illus/illus-maintenance-light.svg';
import illusMDark    from '@btech/assets/illus/illus-maintenance-dark.svg';
import illusNDLight  from '@btech/assets/illus/illus-no-data-light.svg';
import illusNDDark   from '@btech/assets/illus/illus-no-data-dark.svg';
import illusNRLight  from '@btech/assets/illus/illus-no-result-light.svg';
import illusNRDark   from '@btech/assets/illus/illus-no-result-dark.svg';

// Asset imports resolve to a URL string in most bundlers (Vite, esbuild/tsup
// `dataurl`), but Next.js static-image handling returns an object
// (`{ src, height, width }`). Normalize so `<img src>` always gets a string —
// otherwise React coerces the object to "[object Object]" and the asset fails.
const assetUrl = (value: unknown): string =>
  typeof value === 'string' ? value : (value as { src?: string })?.src ?? '';

const ILLUS_MAP: Record<BTEmptyStateVariant, { light: string; dark: string; alt: string }> = {
  '400':               { light: illus400Light, dark: illus400Dark, alt: 'Error 400 illustration' },
  '401':               { light: illus401Light, dark: illus401Dark, alt: 'Error 401 illustration' },
  '404':               { light: illus404Light, dark: illus404Dark, alt: 'Error 404 illustration' },
  '500':               { light: illus500Light, dark: illus500Dark, alt: 'Error 500 illustration' },
  'under-maintenance': { light: illusMLight,   dark: illusMDark,   alt: 'Under maintenance illustration' },
  'no-data':           { light: illusNDLight,  dark: illusNDDark,  alt: 'No data illustration' },
  'no-result':         { light: illusNRLight,  dark: illusNRDark,  alt: 'No result illustration' },
};

const SIMPLE_LABELS: Record<string, string> = {
  'no-data':   "There's no data yet.",
  'no-result': 'No result found.',
};

export function BTEmptyState({
  variant = '404',
  title,
  subtext,
  errorMessage,
  buttonLabel,
  showButton = true,
  onButtonClick,
  className,
}: BTEmptyStateProps) {
  const isError = ERROR_VARIANTS.includes(variant);
  const defaults = EMPTY_STATE_DEFAULTS[variant];

  const resolvedTitle       = title        ?? defaults?.title;
  const resolvedSubtext     = subtext      ?? defaults?.subtext;
  const resolvedErrorMsg    = errorMessage ?? defaults?.errorMessage;
  const resolvedButtonLabel = buttonLabel  ?? defaults?.buttonLabel;

  const showBtn = isError && showButton;
  const illus = ILLUS_MAP[variant];

  const rootClass = [
    'bt-empty-state',
    isError ? 'bt-empty-state--error' : 'bt-empty-state--simple',
    className,
  ].filter(Boolean).join(' ');

  return (
    <div className={rootClass}>
      {/* Illustration — theme-aware; CSS toggles light/dark via [data-mode="dark"] */}
      <div className="bt-empty-state__illus">
        <img
          className="bt-empty-state__illus-img bt-empty-state__illus-img--light"
          src={assetUrl(illus.light)}
          alt={illus.alt}
        />
        <img
          className="bt-empty-state__illus-img bt-empty-state__illus-img--dark"
          src={assetUrl(illus.dark)}
          alt={illus.alt}
        />
      </div>

      {isError ? (
        <>
          <div className="bt-empty-state__text">
            <p className="bt-empty-state__title">{resolvedTitle}</p>
            <p className="bt-empty-state__subtext">{resolvedSubtext}</p>
            <p className="bt-empty-state__error-msg">{resolvedErrorMsg}</p>
          </div>

          {showBtn && (
            <BTButton
              variant="secondary-light"
              size="small"
              label={resolvedButtonLabel}
              onClick={onButtonClick}
            />
          )}
        </>
      ) : (
        <p className="bt-empty-state__label">
          {title ?? SIMPLE_LABELS[variant]}
        </p>
      )}
    </div>
  );
}

export type BTEmptyStateVariant =
  | '400'
  | '401'
  | '404'
  | '500'
  | 'under-maintenance'
  | 'no-data'
  | 'no-result';

export interface BTEmptyStateDefaults {
  title: string;
  subtext: string;
  errorMessage: string;
  buttonLabel: string;
}

export const EMPTY_STATE_DEFAULTS: Record<string, BTEmptyStateDefaults> = {
  '400': {
    title: 'Oops! Something Went Wrong',
    subtext: "We couldn't process your request. Please try again later.",
    errorMessage: 'Error : System Message',
    buttonLabel: 'Reload',
  },
  '401': {
    title: 'No Unauthorized Access',
    subtext: "We couldn't verify your credentials. Please check your login details and try again.",
    errorMessage: 'Error : System Message',
    buttonLabel: 'Go Back',
  },
  '404': {
    title: "This Page isn't Available",
    subtext: "We couldn't find the page you're looking for. It may have been moved or no longer exists.",
    errorMessage: 'Error : System Message',
    buttonLabel: 'Go Back',
  },
  '500': {
    title: "This Page Isn't Working",
    subtext: 'We apologize for the inconvenience, we are currently working on repairs. Please return in a moment.',
    errorMessage: 'Error : System Message',
    buttonLabel: 'Reload',
  },
  'under-maintenance': {
    title: 'This Page Is Under Maintenance',
    subtext: 'We are improving this page, and will be back soon! You can explore other page.',
    errorMessage: 'Error : System Message',
    buttonLabel: 'Go Back',
  },
};

export const ERROR_VARIANTS: BTEmptyStateVariant[] = [
  '400', '401', '404', '500', 'under-maintenance',
];

export interface BTEmptyStateProps {
  variant?: BTEmptyStateVariant;
  title?: string;
  subtext?: string;
  errorMessage?: string;
  buttonLabel?: string;
  showButton?: boolean;
  onButtonClick?: () => void;
  className?: string;
}
